import path from 'path';
import StyleDictionary from 'style-dictionary';
import { fileURLToPath } from 'url';
import { filterUnused } from './processors/filterUnused.js';
import { formatCss } from './processors/formatCss.js';
import { formatDocs } from './processors/formatDocs.js';
import { getTwFormatter } from './processors/formatTwExports.js';
import { parseAssets } from './processors/parseAssets.js';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const resolvePath = (relPath) => {
    return path.resolve(__dirname, relPath);
};
StyleDictionary.registerFilter({
    name: 'filterUnused',
    filter: filterUnused,
});
StyleDictionary.registerParser({
    name: 'parseAssets',
    pattern: /\.json$/,
    parser: parseAssets,
});
StyleDictionary.registerFormat({
    name: 'css/formatCss',
    format: formatCss,
});
StyleDictionary.registerFormat({
    name: 'docs/formatDocs',
    format: formatDocs,
});
StyleDictionary.registerFormat({
    name: 'js/formatTwExports',
    format: getTwFormatter('esm'),
});
StyleDictionary.registerFormat({
    name: 'js/formatTwExportsCjs',
    format: getTwFormatter('cjs'),
});
const config = {
    source: [resolvePath('../design-assets/tokens.json')],
    include: [resolvePath('../design-assets/primitives.json')],
    parsers: ['parseAssets'],
    platforms: {
        'css/raw': {
            transforms: ['name/kebab'],
            files: [
                {
                    destination: resolvePath('../tokens/tokens.css'),
                    format: 'css/formatCss',
                    filter: 'filterUnused',
                    options: {
                        outputReferences: false,
                    },
                },
            ],
        },
        'docs/mappings': {
            transforms: ['name/kebab'],
            files: [
                {
                    destination: resolvePath('../tokens/token-mappings.md'),
                    format: 'docs/formatDocs',
                    filter: 'filterUnused',
                    options: {
                        outputReferences: true,
                    },
                },
            ],
        },
        'js/tailwind-config': {
            transforms: ['name/kebab'],
            files: [
                {
                    format: 'js/formatTwExports',
                    filter: 'filterUnused',
                    destination: resolvePath('../tokens/tokens.js'),
                },
            ],
        },
        'js/tailwind-config-cjs': {
            transforms: ['name/kebab'],
            files: [
                {
                    format: 'js/formatTwExportsCjs',
                    filter: 'filterUnused',
                    destination: resolvePath('../tokens/tokens.cjs'),
                },
            ],
        },
    },
};
/**
 * used for debugging rather than run from cli
 */
const builder = new StyleDictionary(config, { verbosity: 'verbose' });
builder.buildAllPlatforms().then(() => {
    // eslint-disable-next-line no-console
    console.log('done');
});
